"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import { useDropzone } from "react-dropzone";
import { clsx } from "clsx";
import { 
  FileText, Folder, FolderOpen, Link as LinkIcon, CheckCircle, 
  User, ArrowLeft, CalendarDays, UserCheck, UploadCloud, Loader2,
  Columns, X, Minimize2, Maximize2, MousePointer2
} from "lucide-react";

// ... (データ定義 staffList, periods, useCrossSwipe は変更なし。そのまま維持してください) ...
// ※ 長くなるので、上部の定義部分は省略します。以下の `Home` コンポーネントを差し替えてください。

// --- 省略された部分は以前のコードと同じ ---
// (ここに staffList, periods, useCrossSwipe を貼り付けてください)
// もし面倒なら、教えてくれれば「全コード」を出力します！

// --- ★ 新規部品: PDF表示パネル (左右で使い回す用) ---
const PdfPanel = ({ 
  url, 
  title, 
  isActive, 
  onActivate, 
  onClose,
  placeholder 
}: { 
  url: string | null, 
  title: string, 
  isActive: boolean, 
  onActivate: () => void, 
  onClose?: () => void,
  placeholder: string
}) => {
  return (
    <div 
      className={clsx(
        "flex-1 flex flex-col relative transition-all duration-300 border-r border-slate-300 bg-slate-100",
        isActive ? "ring-2 ring-inset ring-blue-500 z-10" : "opacity-80 hover:opacity-100"
      )}
      onClick={onActivate}
    >
      {/* パネルヘッダー */}
      <div className={clsx("h-8 flex items-center justify-between px-3 border-b border-slate-200 text-xs font-bold", isActive ? "bg-blue-50 text-blue-600" : "bg-slate-200 text-slate-500")}>
        <div className="flex items-center gap-2">
           <FileText size={12}/> {title || "No Document"}
        </div>
        {onClose && (
          <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="hover:bg-slate-300 rounded p-1">
            <X size={12}/>
          </button>
        )}
      </div>

      {/* PDF表示エリア */}
      <div className="flex-1 relative overflow-hidden">
        {url ? (
          <iframe src={url} className="w-full h-full border-none" />
        ) : (
          <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300">
             <FileText size={60} />
             <p className="mt-2 text-xs font-bold">{placeholder}</p>
          </div>
        )}
      </div>
    </div>
  );
};

// ... (DropzoneCard も変更なし) ...

export default function Home() {
  // State
  // ... (以前のStateはそのまま維持) ...
  const [staffIdx, setStaffIdx] = useState(0);
  const [activeClientIdx, setActiveClientIdx] = useState(0);
  const [mode, setMode] = useState<'year' | 'month'>('year');
  const [activePeriodIdx, setActivePeriodIdx] = useState(1);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadedStatus, setUploadedStatus] = useState<Record<string, boolean>>({'決算報告書': true});
  const [toast, setToast] = useState<{show: boolean, icon: any, title: string, msg: string}>({ show: false, icon: null, title: "", msg: "" });

  // ★ ビューワー用 State の強化
  const [viewerOpen, setViewerOpen] = useState(false);
  const [splitMode, setSplitMode] = useState(false); // 画面分割モードか？
  
  // Left Panel (Main)
  const [mainDoc, setMainDoc] = useState<{title: string, url: string | null}>({ title: "", url: null });
  // Right Panel (Sub)
  const [subDoc, setSubDoc] = useState<{title: string, url: string | null}>({ title: "", url: null });
  
  const [activePanel, setActivePanel] = useState<'main' | 'sub'>('main'); // どっちのパネルを操作中か

  // ... (Refs, showToast, switchStaff, switchMode, handleScroll, scrollToCenter は変更なし) ...

  // --- アップロード処理 (強化版) ---
  const handleUpload = useCallback(async (file: File, docTitle: string) => {
    const localUrl = URL.createObjectURL(file);
    setIsUploading(true);
    showToast(UploadCloud, "UPLOADING", `${docTitle} を読み込み中...`);

    // ★ 今アクティブなパネルにロードする
    if (activePanel === 'main') {
      setMainDoc({ title: docTitle, url: localUrl });
    } else {
      setSubDoc({ title: docTitle, url: localUrl });
    }
    
    // 状態更新
    setUploadedStatus(prev => ({ ...prev, [docTitle]: true }));
    setViewerOpen(true);

    // API送信
    const formData = new FormData();
    formData.append("file", file);
    try {
      await fetch("/api/upload", { method: "POST", body: formData });
      showToast(CheckCircle, "SAVED", "保存しました");
    } catch (e) { console.error(e); } finally { setIsUploading(false); }
  }, [activePanel, showToast]); // activePanelに依存

  // --- カードクリック時の処理 ---
  const handleCardClick = (title: string) => {
    // 既に開いていれば何もしない等のロジックも可だが、今回はシンプルに
    // 「アクティブなパネル」にその書類をロードする挙動にする
    // ※本来はここでもURLを取得するが、今はダミーとして空URLまたは以前のURLを使う想定
    //  （デモ用にアップロード済なら既存URLを表示したいが、URL管理していないのでタイトルだけセット）
    
    setViewerOpen(true);
    if (activePanel === 'main') {
       setMainDoc(prev => ({ ...prev, title: title, url: prev.title === title ? prev.url : null })); 
       // ※↑同じタイトルならURL維持、違うならリセット(要再アップロード)という簡易実装
    } else {
       setSubDoc(prev => ({ ...prev, title: title, url: prev.title === title ? prev.url : null }));
    }
  };

  // ... (Render部分の DropzoneCard や Grid部分) ...
  // Grid内のonClickを handleCardClick に書き換える必要があります

  return (
    <div className="text-slate-600 h-screen flex flex-col bg-slate-100 font-sans overflow-hidden select-none">
       {/* ... (Nav, Aside, Main の構造は維持) ... */}
       {/* ここは長いので、変更点である「ビューワー」だけ下に書きます */}

       {/* === ビューワー (Split View対応) === */}
       {viewerOpen && (
        <div className="fixed inset-0 bg-slate-900/95 z-50 flex animate-fade-in-up flex-col">
           
           {/* ヘッダー */}
           <header className="h-14 bg-slate-800 border-b border-slate-700 flex items-center justify-between px-4 z-20 flex-shrink-0">
             <div className="flex items-center gap-4">
                 <button onClick={() => setViewerOpen(false)} className="text-slate-400 hover:text-white flex items-center gap-2 text-sm font-bold">
                   <ArrowLeft size={16} /> 戻る
                 </button>
                 <div className="h-6 w-px bg-slate-600"></div>
                 
                 {/* 現在の作業対象を表示 */}
                 <div className="text-white font-bold text-sm flex items-center gap-2">
                    <span className="bg-blue-600 px-2 py-0.5 rounded text-[10px]">MAIN</span>
                    {mainDoc.title || "未選択"}
                    {splitMode && (
                      <>
                        <span className="text-slate-500">vs</span>
                        <span className="bg-indigo-600 px-2 py-0.5 rounded text-[10px]">SUB</span>
                        {subDoc.title || "未選択"}
                      </>
                    )}
                 </div>
             </div>

             <div className="flex items-center gap-3">
                 {/* ★ 画面分割ボタン */}
                 <button 
                   onClick={() => {
                     setSplitMode(!splitMode);
                     if (!splitMode) setActivePanel('sub'); // 分割したら右側をアクティブに
                   }}
                   className={clsx(
                     "flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all border",
                     splitMode 
                       ? "bg-indigo-600 text-white border-indigo-500 shadow-[0_0_15px_rgba(79,70,229,0.5)]" 
                       : "bg-slate-700 text-slate-300 border-slate-600 hover:bg-slate-600"
                   )}
                 >
                    <Columns size={14} />
                    {splitMode ? "Single View" : "Compare"}
                 </button>
                 
                 <button className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-1.5 rounded-lg text-xs font-bold shadow-lg flex items-center gap-2">
                    <CheckCircle size={14} /> 完了
                 </button>
             </div>
           </header>

           {/* ビューワー本体エリア */}
           <div className="flex-1 flex overflow-hidden relative">
              
              {/* 左パネル (Main) */}
              <PdfPanel 
                url={mainDoc.url} 
                title={mainDoc.title} 
                isActive={activePanel === 'main'}
                onActivate={() => setActivePanel('main')}
                placeholder="Select Main Document"
              />

              {/* 右パネル (Sub) - Splitモード時のみ表示 */}
              {splitMode && (
                <PdfPanel 
                  url={subDoc.url} 
                  title={subDoc.title} 
                  isActive={activePanel === 'sub'}
                  onActivate={() => setActivePanel('sub')}
                  onClose={() => setSplitMode(false)}
                  placeholder="Select Comparison Document"
                />
              )}

           </div>

           {/* フッター: ドロップゾーンのヒント */}
           <div className={clsx("h-8 bg-slate-800 border-t border-slate-700 flex items-center justify-center text-[10px] font-bold transition-colors", activePanel === 'main' ? "text-blue-400" : "text-indigo-400")}>
              <MousePointer2 size={12} className="mr-2"/>
              {activePanel === 'main' ? "MAIN PANEL ACTIVE" : "SUB PANEL ACTIVE"} - Drop file or select from grid to load here
           </div>
        </div>
      )}
    </div>
  );
}